### Issue 3: Directory Traversal in `/api/browse`

Restrict browsing to allowed directories:

```csharp
// Add allowed base directories after line 26
var allowedBrowseDirs = new[]
{
    Path.GetFullPath(Path.Combine(app.Environment.ContentRootPath, "..", "Orchestrations")),
    Path.GetFullPath(Path.Combine(app.Environment.ContentRootPath, "..", "MCPs")),
    // Add other allowed directories here
};

// Refactor /api/browse (line 289-316)
app.MapPost("/api/browse", (BrowseRequest request) =>
{
    try
    {
        var directory = request.Directory?.Trim();
        if (string.IsNullOrEmpty(directory))
            return Results.BadRequest(new { error = "Directory path is required." });

        var fullPath = Path.GetFullPath(directory);

        // Validate directory is within allowed paths
        if (!allowedBrowseDirs.Any(allowed => 
            fullPath.Equals(allowed, StringComparison.OrdinalIgnoreCase) ||
            fullPath.StartsWith(allowed + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase)))
        {
            return Results.BadRequest(new { error = "Access to this directory is not allowed." });
        }

        if (!Directory.Exists(fullPath))
            return Results.BadRequest(new { error = $"Directory not found: {directory}" });

        var files = Directory.GetFiles(fullPath, "*.json", SearchOption.TopDirectoryOnly)
            .Select(f => new
            {
                name = Path.GetFileName(f),
                path = f,
                size = new FileInfo(f).Length,
            })
            .OrderBy(f => f.name)
            .ToArray();

        return Results.Json(new { directory = fullPath, files }, jsonOptions);
    }
    catch (Exception ex)
    {
        return Results.BadRequest(new { error = ex.Message });
    }
});
```

